import {{ Injectable }} from '@nestjs/common';
import {{ AccountService }} from './models/account.model';
import {{ AccountServiceRepository }} from './repositories/account.repository';

@Injectable()
export class AccountServiceService {{
  constructor(
    private readonly repository: AccountServiceRepository,
  ) {{}}

  async findAll(): Promise<AccountService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<AccountService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<AccountService>): Promise<AccountService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<AccountService>): Promise<AccountService> {{
    return this.repository.update(id, data);
  }}
}}
